<template>
  <div class="row">
    <div class="col-md-12">
      <vuestic-widget style="min-height: 350px" :headerText="'Predračun'">
        <div class="form-elements">
          <div class="row">
            <div class="col-md-12">
              <div class="row">
                <div class="col-md-3">
                  <div v-if="racuni.length" class="form-group with-icon-left">
                    <div class="input-group">
                      <input
                        onpaste="return false;"
                        autocomplete="off"
                        id="input-icon-left"
                        title=" "
                        name="input-icon-left"
                        v-model="text"
                        required
                      />
                      <i
                        class="glyphicon glyphicon-search icon-left input-icon search-icon"
                      ></i>
                      <label class="control-label" for="input-icon-left">{{
                        "Pretraga"
                      }}</label>
                      <i class="bar"></i>
                    </div>
                  </div>
                </div>

                <div class="col-md-6">
                    <!--  -->
        <div class="form-group with-icon-left pull-left" style="padding-left: 2%">
          <vuestic-simple-select
            class="form-group with-icon-right"
            label="Izbor"
            v-model="range"
            name="range"
            required
            title=" "
            ref="range"
            v-bind:options="ranges"
          ></vuestic-simple-select>
        </div>
                
                </div>



                



                <div v-if="racuni.length" class="col-md-12">
                  <div class="table-responsive">
                    <table class="table table-striped first-td-padding">
                      <thead>
                        <tr>
                          <td>{{ "" }}</td>
                          <td>{{ "PARTNER" }}</td>
                          <td>{{ "ID" }}</td>
                          <td>{{ "IME" }}</td>
                          <td>{{ "PREZIME" }}</td>
                          <td>{{ "GODIŠTE" }}</td>
                          <td>{{ "UKUPNO" }}</td>
                          <td>{{ "% POPUST" }}</td>
                          <td>{{ "ZA PLATITI" }}</td>
                          <td>{{ "DATUM" }}</td>
                          <td>{{ "UPDATED" }}</td>
                          <td></td>
                        </tr>
                      </thead>
                      <tbody>
                        <tr v-for="element in filtered" :key="element._id">
                           <td>
                          <i
                            v-if="element.valid === false"
                            style="font-size:12px;"
                            v-bind:class="{
                              'fa fa-exclamation-triangle icon-right input-icon error-icon': true,
                            }"
                          ></i>
                          <i
                            v-if="element.valid === true"
                            style="font-size:14px;"
                            v-bind:class="{
                              'fa fa-check success-icon icon-right input-icon': true,
                            }"
                          ></i>
                        </td>
                          <td>{{ element.partner }}</td>
                          <td>{{ element.pid }}</td>
                          <td>{{ element.ime }}</td>
                          <td>{{ element.prezime }}</td>
                          <td>{{ element.godiste }}</td>
                          <td>{{ element.nodiscount }}</td>
                          <td>{{ element.discount }}</td>

                          <td
                            v-if="
                              element.datum != 'CASH' &&
                              element.datum != 'VIRMAN' &&
                              element.datum != 'TOTAL'
                            "
                          >
                            {{ element.total }}
                          </td>
                          <td v-if="element.datum === 'CASH'">
                            <span style="color: #e34a4a">
                              {{ element.total }}</span
                            >
                          </td>
                          <td v-if="element.datum === 'VIRMAN'">
                            <span style="color: #e34a4a">
                              {{ element.total }}</span
                            >
                          </td>
                          <td v-if="element.datum === 'TOTAL'">
                            <strong style="color: #e34a4a">
                              {{ element.total }}</strong
                            >
                          </td>

                          <td
                            v-if="
                              element.datum != 'CASH' &&
                              element.datum != 'VIRMAN' &&
                              element.datum != 'TOTAL'
                            "
                          >
                            {{ element.datum }}
                          </td>
                          <td v-if="element.datum === 'CASH'">
                            <span style="color: #e34a4a">
                              {{ element.datum }}</span
                            >
                          </td>
                          <td v-if="element.datum === 'VIRMAN'">
                            <span style="color: #e34a4a">
                              {{ element.datum }}</span
                            >
                          </td>
                          <td v-if="element.datum === 'TOTAL'">
                            <strong style="color: #e34a4a">
                              {{ element.datum }}</strong
                            >
                          </td>

                          <!-- <td>{{ element.datum }}</td> -->
                          <td>{{ element.updated_by }}</td>
                          <td
                            align="center"
                            v-if="
                              element.datum != 'CASH' &&
                              element.datum != 'VIRMAN' &&
                              element.datum != 'TOTAL'
                            "
                          >
                            <i
                              @dblclick.prevent="Delete($event, element)"
                              v-bind:id="element._id"
                              style="color: #e34a4a"
                              class="fa fa-trash-o"
                            ></i>
                          </td>

                          <td
                            align="center"
                            v-if="
                              element.datum === 'CASH' ||
                              element.datum === 'VIRMAN' ||
                              element.datum === 'TOTAL'
                            "
                          ></td>
                        </tr>
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div class="col-md-4">
            <fieldset>
              <button
                v-show="racuni.length > 0"
                style="text-transform: none; border: 0px; border-radius: 0px"
                class="btn btn-secondary btn-sm"
                @click.prevent="Download()"
              >
                <span class="fa fa-file-excel-o"></span>
                {{ " XLSX Download" }}
              </button>
            </fieldset>
          </div>

          <div class="row">
            <div class="col-md-12">
              <div class="col-md-6">
                <loading
                  :active.sync="isLoading"
                  :can-cancel="false"
                  :on-cancel="onCancel"
                  color="#e34a4a"
                  :is-full-page="fullPage"
                ></loading>
              </div>
              <div class="col-md-6">
                <button v-if="false" @click.prevent="Test">
                  {{ "Loading..." }}
                </button>
              </div>
            </div>
          </div>
        </div>
      </vuestic-widget>
    </div>

    <div class="row">
      <div class="col-md-12">
        <div class="col-md-6">
          <loading
            :active.sync="isLoading"
            :can-cancel="false"
            :on-cancel="onCancel"
            color="#e34a4a"
            :is-full-page="fullPage"
          ></loading>
        </div>
        <div class="col-md-6">
          <button v-if="false" @click.prevent="Test">{{ "Loading..." }}</button>
        </div>
      </div>
    </div>
  </div>
</template>



<script>
import Vue from "vue";
import BadgeColumn from "./BadgeColumn.vue";
import { http } from "../../../config/config.js";
import { bus } from "../../main";

import Loading from "vue-loading-overlay";
import "vue-loading-overlay/dist/vue-loading.css";

Vue.component("badge-column", BadgeColumn);

export default {
  name: "izvjestaj",

  components: {
    Loading,
  },

  data() {
    return {
      show: true,

      isLoading: false,
      fullPage: true,

      TOTAL: "0",
      CASH: "0",
      VIRMAN: "0",
      racuni: [],
      filtered: [],
      text: "",
      range: "DANAS",
      ranges: ["JUČER", "DANAS"],

      timestamp: "",
    };
  },

  created() {
    this.timestamp = (
      new Date().getTime() -
      new Date().getTimezoneOffset() * 60000
    ).toString();

    (this.isLoading = true),
      http
        .post("/racuni/report/", {
          token: this.$store.state.token,
          site: this.$store.state.site,
          range: this.range,
          timestamp: this.timestamp,
        })
        .then((res) => {
          if (res.data.success) {
            this.TOTAL = res.data.total;
            this.CASH = res.data.cash;
            this.VIRMAN = res.data.virman;
            console.log("CASH: " + res.data.cash);
            console.log("VIRMAN: " + res.data.virman);
            console.log("TOTAL: " + res.data.total);
            this.racuni = res.data.racuni;
            this.filtered = res.data.racuni;
            this.text = "";
            this.isLoading = false;
          } else {
            this.isLoading = false;
          }
        });
  },

  mounted() {},

  watch: {
    text: function () {
      this.filtered = [];
      this.racuni.forEach((element) => {
        if (
          element.ime.toLowerCase().includes(this.text.toLowerCase()) ||
          element.prezime.toLowerCase().includes(this.text.toLowerCase()) ||
          element.partner.toLowerCase().includes(this.text.toLowerCase())
        ) {
          this.filtered.push(element);
        }
      });
    },

    range: function () {
      this.timestamp = (
      new Date().getTime() -
      new Date().getTimezoneOffset() * 60000
    ).toString();

    (this.isLoading = true),
      http
        .post("/racuni/report/", {
          token: this.$store.state.token,
          site: this.$store.state.site,
          range: this.range,
          timestamp: this.timestamp,
        })
        .then((res) => {
          if (res.data.success) {
            this.TOTAL = res.data.total;
            this.CASH = res.data.cash;
            this.VIRMAN = res.data.virman;
            console.log("CASH: " + res.data.cash);
            console.log("VIRMAN: " + res.data.virman);
            console.log("TOTAL: " + res.data.total);
            this.racuni = res.data.racuni;
            this.filtered = res.data.racuni;
            this.text = "";
            this.isLoading = false;
          } else {
            this.isLoading = false;
          }
        });
    },

  },

  beforeDestroy() {},

  methods: {
    Download() {
      http
        .get(
          "izvjestaj/xlsx/download?token=" +
            this.$store.state.token +
            "&filename=" +
            this.timestamp,
          { responseType: "blob" }
        )
        .then((res) => {
          // console.log(res);
          if (res.status == 200) {
            const url = window.URL.createObjectURL(new Blob([res.data]));
            const link = document.createElement("a");
            link.href = url;
            link.setAttribute("download", this.timestamp + ".xlsx");
            document.body.appendChild(link);
            link.click();
          }
        });
    },

    Delete(event, element) {
      console.log(element);
      this.isLoading = true;
      http
        .post("racuni/delete", {
          racun: element,
          token: this.$store.state.token,
          site: this.$store.state.site,
        })
        .then((res) => {
          if (res.data.success) {
            console.log(res.data);

            this.timestamp = (
              new Date().getTime() -
              new Date().getTimezoneOffset() * 60000
            ).toString();

            http
              .post("/racuni/report/", {
                token: this.$store.state.token,
                site: this.$store.state.site,
                range: this.range,
                timestamp: this.timestamp,
              })
              .then((res) => {
                if (res.data.success) {
                  this.TOTAL = res.data.total;
                  this.CASH = res.data.cash;
                  this.VIRMAN = res.data.virman;
                  console.log("CASH: " + res.data.cash);
                  console.log("VIRMAN: " + res.data.virman);
                  console.log("TOTAL: " + res.data.total);
                  this.racuni = res.data.racuni;
                  this.filtered = res.data.racuni;
                  this.text = "";
                  this.isLoading = false;
                } else {
                  this.isLoading = false;
                }
              });
          } else {
            this.isLoading = false;
          }
        });
    },

    Test() {
      this.isLoading = true;

      setTimeout(() => {
        this.isLoading = false;
      }, 2000);
    },
    onCancel() {},
  },
};
</script>

<style lang="scss" scoped>
@import "../../sass/_variables.scss";
@import "../../../node_modules/bootstrap/scss/functions";
@import "../../../node_modules/bootstrap/scss/variables";
@import "../../../node_modules/bootstrap/scss/mixins/breakpoints";

.abc-checkbox,
.abc-radio {
  display: flex !important;
  justify-content: flex-start;
}

input[type="checkbox"]:disabled + label,
input[type="radio"]:disabled + label,
input[type="checkbox"]:disabled,
input[type="radio"]:disabled {
  cursor: not-allowed;
}
.chart-container {
  padding: 0 2rem;
  height: 24rem;
}
</style>



